import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.CE5oItKu.js";const _=JSON.parse('{"title":"安全规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/06-security.md","filePath":"mango-pmo/rules/backend/06-security.md"}'),t={name:"mango-pmo/rules/backend/06-security.md"};function o(n,a,h,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="安全规范" tabindex="-1">安全规范 <a class="header-anchor" href="#安全规范" aria-label="Permalink to &quot;安全规范&quot;">​</a></h1><h2 id="_1-配置安全" tabindex="-1">1. 配置安全 <a class="header-anchor" href="#_1-配置安全" aria-label="Permalink to &quot;1. 配置安全&quot;">​</a></h2><ul><li>密钥、口令、地址、账号必须从配置读取。</li><li>禁止硬编码敏感信息。</li><li>敏感配置不提交到仓库。</li></ul><h2 id="_2-输入安全" tabindex="-1">2. 输入安全 <a class="header-anchor" href="#_2-输入安全" aria-label="Permalink to &quot;2. 输入安全&quot;">​</a></h2><ul><li>所有外部输入必须校验。</li><li>字符串输入必须限制长度和格式。</li><li>高风险内容必须做过滤或转义。</li></ul><h2 id="_3-数据访问安全" tabindex="-1">3. 数据访问安全 <a class="header-anchor" href="#_3-数据访问安全" aria-label="Permalink to &quot;3. 数据访问安全&quot;">​</a></h2><ul><li>所有 SQL 必须参数化。</li><li>禁止拼接 SQL。</li><li>权限相关查询必须显式控制范围。</li></ul><h2 id="_4-权限控制" tabindex="-1">4. 权限控制 <a class="header-anchor" href="#_4-权限控制" aria-label="Permalink to &quot;4. 权限控制&quot;">​</a></h2><ul><li>受保护接口必须做权限校验。</li><li>权限码命名保持统一。</li><li>不允许只在前端做权限控制。</li></ul><h2 id="_5-敏感数据" tabindex="-1">5. 敏感数据 <a class="header-anchor" href="#_5-敏感数据" aria-label="Permalink to &quot;5. 敏感数据&quot;">​</a></h2><ul><li>敏感字段按需要脱敏返回。</li><li>日志禁止打印敏感内容。</li><li>密码只允许加密存储。</li></ul><h2 id="_6-传输安全" tabindex="-1">6. 传输安全 <a class="header-anchor" href="#_6-传输安全" aria-label="Permalink to &quot;6. 传输安全&quot;">​</a></h2><ul><li>外部通信默认使用 HTTPS。</li><li>不使用已淘汰协议和弱加密配置。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>在代码里写明文口令</li><li>日志输出 token、密码、证件号</li><li>只做页面权限，不做接口权限</li></ul>',15)])])}const m=l(t,[["render",o]]);export{_ as __pageData,m as default};
